-- Enriches the harbour directory from an official Estonian guest-harbour
-- registry export (veebikaart.ee) covering the whole coastline, not just
-- Tallinn bay. The source file had a partial encoding failure before it
-- reached this project: its header row and several categorical columns
-- (non-ASCII text, apparently Russian) were already replaced with literal
-- '?' bytes by an earlier export step -- unrecoverable, not a charset
-- guessing problem. What survived intact: harbour name, code, address,
-- GPS, phone, email, website, and an Estonian amenities list, which is
-- translated to English below. A handful of corrupted placeholder values
-- that leaked into website/email/phone/address ('not specified', garbled)
-- were cleaned to null rather than inserted as garbage text.

alter table harbour add column harbour_code varchar(10);
alter table harbour add column address text;
alter table harbour add column website varchar(255);
alter table harbour add column email varchar(255);
alter table harbour add column amenities text;
alter table harbour add column source_url text;

-- Real-world location correction: Kelnase is in Viimsi vald, not on
-- Prangli island as an earlier guess in this project assumed. Renaming
-- (not just fixing the address) because the old name is user-facing in
-- bot replies -- the substring "Kelnase" that /sail and /harbour match
-- on is preserved, so this doesn't break existing lookups.
update harbour set name = 'Kelnase (Viimsi)' where name = 'Kelnase (Prangli)';

-- 6 existing harbours enriched with authoritative contact
-- details and corrected coordinates from the registry export.
